      [{title:'Создание MCP-сервера',description:'Простой MCP-сервер на TypeScript с одним инструментом.',code:`import { McpServer } from '@modelcontextprotocol/sdk/server/mcp.js';\nimport { StdioServerTransport } from '@modelcontextprotocol/sdk/server/stdio.js';\n\nconst server = new McpServer({ name: 'my-server', version: '1.0.0' });\n\nserver.tool('calculate', { expression: z.string() }, async ({ expression }) => {\n  const result = eval(expression); // Упрощённо\n  return { content: [{ type: 'text', text: String(result) }] };\n});\n\nconst transport = new StdioServerTransport();\nawait server.connect(transport);`,language:'typescript'}],
