      [{topic:'MCP Server',slug:'mcp-server',categorySlug:'mcp'},{topic:'MCP Client',slug:'mcp-client',categorySlug:'mcp'},{topic:'MCP Tools',slug:'mcp-tools',categorySlug:'mcp'}]
